import cv2
backends = [\('Default', None\), \('CAP_DSHOW', cv2.CAP_DSHOW\), \('CAP_MSMF', cv2.CAP_MSMF\)]
print\('Scanning camera indices 0-4 across backends...'\)
for idx in range\(5\):
    for name, backend in backends:
        try:
            cap = cv2.VideoCapture\(idx, backend\) if backend is not None else cv2.VideoCapture\(idx\)
            opened = cap.isOpened\(\)
            if opened:
                w = int\(cap.get\(cv2.CAP_PROP_FRAME_WIDTH\)\)
                h = int\(cap.get\(cv2.CAP_PROP_FRAME_HEIGHT\)\)
                fps = cap.get\(cv2.CAP_PROP_FPS\)
                print\(f'  index={idx} backend={name}: OPEN  {w}x{h} @ {fps:.0f}fps'\)
            else:
                print\(f'  index={idx} backend={name}: FAILED'\)
            cap.release\(\)
        except Exception as e:
            print\(f'  index={idx} backend={name}: ERROR - {e}'\)
")
